  ('dietitian-moex-01998', 'dietitian', 'dietitian-moex-107-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '當飲食中缺乏醣類或當脂肪分解代謝增加時，可能會導致酮酸中毒。主要是因為下列何種物質的含量不 足，使TCA循環無法順利進行，而導致酮體的產生？', '["Acetyl-CoA", "Pyruvate", "Oxaloacetate", "Acetoacetyl-CoA"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "81a07d782b21", "answer_pdf_sha1": "811659f781aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
